function minCostClimbingStairs(cost) {
  const n = cost.length;
  let a = cost[0], b = cost[1];
  for (let i = 2; i < n; i++) {
    const c = cost[i] + Math.min(a, b);
    a = b;
    b = c;
  }
  return Math.min(a, b);
}

